INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2616, 224194, 13, 2397, '简单的女孩', '&nbsp;&nbsp;刚看了一篇小说，心里有种柔软的感觉。一篇很美的，不带任何功利的爱情小说。有很久没有看过这种文章，没有遇过这种事了。大家因为害怕伤害，总是以及时行乐的态度对待每一段感情，于是再一次被伤害，再一次落寞，孑然的徘徊，在拥挤的大街，在安静的房门后。就是这样，失去再失去，直到一无所有。
<br>&nbsp;&nbsp;&nbsp;&nbsp;故事里的女孩子是这种时代少见的娴静女孩。她年纪小小的，在乎和担心的全是家人和朋友。平凡的恬静的淡淡微笑的女孩，有着最善良的心，最温和的笑容，和世上最好的厨艺。很感动，在这个时代真的还存在这么简单和安静的女孩吗？！
<br>&nbsp;&nbsp;&nbsp;长这么大，从来只知道抱怨，自我感觉很良好啊。很怀疑，为什么却只过着这种孤单的日子。每一天，都会听到朋友们相爱的消息，我却呆呆的在家里盯着屏幕，把泪落在键盘上。只是这样的日子，觉得孤单。而音箱里流泻出的音乐像是婴儿的哭泣。是谁在说着，没有要求，牵牵手就像旅游。就是这样吧，本来以为就会这样自我感觉良好，落寞而沉寂的过下去，在沙发里，在床上慢慢，慢慢变成植物。&nbsp;&nbsp;
<br>&nbsp;&nbsp;&nbsp;&nbsp;却在今天，被一篇文章给感动，被一种女孩感动。如果像那个女孩一样，每天微笑，不害怕，不抱怨，或许，能和她一样幸福。而眼泪也可以落在心爱的人的胸膛上。', '刚看了一篇小说，心里有种柔软的感觉。一篇很美的，不带任何功利的爱情小说。有很久没有看过这种文章，没有遇过这种事了。大家因为害怕伤害，总是以及时行乐的态度对待每一段感情，于是再一次被伤害，再一次落寞，孑然的徘徊，在拥挤的大街，在安静的房门后。就是这样，失去再失去，直到一无所有。

故事里的女孩子是这种时代少见的娴静女孩。她年纪小小的，在乎和担心的全是家人和朋友。平凡的恬静的淡淡微笑的女孩，有着最善良的心，最温和的笑容，和世上最好的厨艺。很感动，在这个时代真的还存在这么简单和安静的女孩吗？！

长这么大，从来只知道抱怨，自我感觉很良好啊。很怀疑，为什么却只过着这种孤单的日子。每一天，都会听到朋友们相爱的消息，我却呆呆的在家里盯着屏幕，把泪落在键盘上。只是这样的日子，觉得孤单。而音箱里流泻出的音乐像是婴儿的哭泣。是谁在说着，没有要求，牵牵手就像旅游。就是这样吧，本来以为就会这样自我感觉良好，落寞而沉寂的过下去，在沙发里，在床上慢慢，慢慢变成植物。

却在今天，被一篇文章给感动，被一种女孩感动。如果像那个女孩一样，每天微笑，不害怕，不抱怨，或许，能和她一样幸福。而眼泪也可以落在心爱的人的胸膛上。', NULL, '2004-02-02 01:18:00', 5, '20040211192934_bbsid_224194_board_13_7513317af2.html', '20040211192934');
